#import os#import csvfrom pyglottolog import Glottolog, monsterimport loggingdef get_log():    logging.basicConfig(level=logging.INFO)    log=logging.getLogger("pyglottolog")    f=logging.FileHandler("monster.log")    log.addHandler(f)    return logdef run():    api = Glottolog('.')        log=get_log()    monster.compile(api, log = log, rebuild = True)if __name__ == "__main__":    run()